const uint8_t *nav_glyph16_builtin_get(uint16_t unicode)
{
  uint8_t i;
  for (i = 0U; i < NAV_BUILTIN_GLYPH_COUNT; i++)
  {
    if (s_nav_builtin_glyphs[i].unicode == unicode)
    {
      return s_nav_builtin_glyphs[i].mat;
    }
  }
  return NULL;
}
